-- Fix vape cartridges: $35-$55 per 1g cart (3500-5500 cents per unit, not per gram)
UPDATE products SET price = 3500, retailPrice = 5500 WHERE name LIKE '%Cart%' AND category = 'vapes';
UPDATE products SET price = 3500, retailPrice = 5500 WHERE category = 'vapes';

-- Fix edibles: $15-$25 per 100mg unit (1500-2500 cents per unit)
UPDATE products SET price = 1800, retailPrice = 2500 WHERE name LIKE '%Gummy%' AND category = 'edibles';
UPDATE products SET price = 1800, retailPrice = 2500 WHERE category = 'edibles';

-- Fix concentrates/shatter: $30-$50 per gram (3000-5000 cents)
UPDATE products SET price = 3500, retailPrice = 5000 WHERE name LIKE '%Shatter%' AND category = 'concentrates';
UPDATE products SET price = 3500, retailPrice = 5000 WHERE category = 'concentrates';

-- Fix pre-rolls: $10-$15 per gram equivalent (1000-1500 cents)
UPDATE products SET price = 1200, retailPrice = 1600 WHERE name LIKE '%Pre-Roll%' AND category = 'pre-rolls';
UPDATE products SET price = 1200, retailPrice = 1600 WHERE category = 'pre-rolls';

-- Verify all categories now have correct prices
SELECT category, COUNT(*) as count, MIN(price) as min_price_cents, MAX(price) as max_price_cents FROM products GROUP BY category;

